    // Adjust column names (user_id, username, email, first_name, last_name, bio)
    // to match your custom table's schema.
    $user_data = $wpdb->get_row(
        $wpdb->prepare(
            "SELECT user_id, username, email, first_name, last_name, bio FROM %i WHERE user_id = %d",
            $custom_users_table,
            $user_id
        )
    );

