    <div class="custom-user-profile">
        <h2><?php echo esc_html($user_data->first_name . ' ' . $user_data->last_name); ?></h2>
        <p><strong>Username:</strong> <?php echo esc_html($user_data->username); ?></p>
        <p><strong>Email:</strong> <?php echo esc_html($user_data->email); ?></p>
